inline Eigen::MatrixXd xwxt(const Eigen::MatrixXd& X, const Eigen::MatrixXd& w) 
{
    const int n(X.rows());
    Eigen::MatrixXd XwXt(Eigen::MatrixXd(n, n).setZero().
                             selfadjointView&lt;Eigen::Lower&gt;().rankUpdate(X * w.array().sqrt().matrix().asDiagonal()));
    return (XwXt);
}

