        if (min_dim &lt; 1000 && ratio &gt; 100) {
            return RECTANGULAR_EXTREME;
        } else if (max_dim &lt; 10000 && ratio &lt; 5) {
            return SQUARE_SMALL;
        } else if (max_dim &lt; 100000 && ratio &lt; 5) {
            return SQUARE_LARGE;  
        } else if (ratio &lt; 5) {
            return SQUARE_EXTREME;
        } else {
