                            }
                        }
                    }

                    #pragma omp ordered
                    {
                        for ( int j = init; j &lt; colstoRead ; j++) { // Rows

                            if( static_cast&lt;int&gt;(offset[0]) + j &lt; verticalData.cols()) {
