            // FALLBACK: Block-wise computation for large matrices (n_vars &gt; 500)
                int block_size = std::min(128, std::max(32, n_vars / 8));
            int num_blocks = (n_vars + block_size - 1) / block_size;

#pragma omp parallel for schedule(dynamic) if(n_vars &gt; 1000)
