                dims[1] = Rcpp::as&lt;Rcpp::DataFrame&gt;(obj).length();

            } else {
                dims[0] = 0;
                dims[1] = 0;
            }

        } catch(std::exception& ex) {
            throw std::runtime_error(std::string("c++ exception getObjecDataType: ") + ex.what());
        }

        return(dims);
    }

