        std::vector&lt;hsize_t&gt; stride = {1, 1},
                             block = {1, 1},
                             offset = {0, 0},
                             count = {0, 0};


        block_size = get_block_size(wsize, dims_out[1], dims_out[0]);

        count[1] = dims_out[1];
        //.. 20260224 ..// if( block_size &lt; dims_out[0] )
        //.. 20260224 ..//     count[0] = block_size;
        //.. 20260224 ..//  else
        //.. 20260224 ..//      count[0] = dims_out[0];

