inline std::tuple&lt;int, int&gt; validateSpectraParams(int n, int k, int ncv) {
        if (k &lt;= 0) k = std::min(n, 6);
        if (k &gt;= n) k = n - 1;

        if (ncv &lt;= 0)
            ncv = std::min(n, std::max(2 * k + 1, k + 2));

        ncv = std::max(ncv, k + 2);
        ncv = std::min(ncv, n);
        if (ncv - k &lt; 2)
            ncv = std::min(n, k + 2);

        return std::make_tuple(k, ncv);
